{"file_path": "/project/ktlint-ruleset-standard/src/test/kotlin/com/pinterest/ktlint/ruleset/standard/rules/IndentationRuleIssue2167Test.kt", "content": "package com.pinterest.ktlint.ruleset.standard.rules

import com.pinterest.ktlint.test.KtLintAssertThat.Companion.assertThatRule
import com.pinterest.ktlint.test.MULTILINE_STRING_QUOTE
import org.junit.jupiter.api.Test

/**
 * Test cases for GitHub issue #2167:
 * "Indentation rule inconsistently identifies issues with multiline string closing quotes between functions and properties"
 *
 * @see <a href="https://github.com/pinterest/ktlint/issues/2167">GitHub Issue #2167</a>
 */
internal class IndentationRuleIssue2167Test {
    private val indentationRuleAssertThat = assertThatRule { IndentationRule() }

    @Test
    fun `Given a function body expression with multiline string and closing quotes at column 0`() {
        val code =
            """
            fun foo() = $MULTILINE_STRING_QUOTE
                <!--suppress XmlUnusedNamespaceDeclaration -->
                <manifest xmlns:android="http://schemas.android.com/apk/res/android"/>
            $MULTILINE_STRING_QUOTE.trimIndent()
            """.trimIndent()
        indentationRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Given a property with multiline string and closing quotes at column 0`() {
        val code =
            """
            val foo = $MULTILINE_STRING_QUOTE
                <!--suppress XmlUnusedNamespaceDeclaration -->
                <manifest xmlns:android="http://schemas.android.com/apk/res/android"/>
            $MULTILINE_STRING_QUOTE.trimIndent()
            """.trimIndent()
        indentationRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Given a function body block with multiline string returned`() {
        val code =
            """
            fun foo2(): String {
                return $MULTILINE_STRING_QUOTE
                    <!--suppress XmlUnusedNamespaceDeclaration -->
                    <manifest xmlns:android="http://schemas.android.com/apk/res/android"/>
                $MULTILINE_STRING_QUOTE.trimIndent()
            }
            """.trimIndent()
        indentationRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Given a function body expression with multiline string and closing quotes at one indent level`() {
        // This should also be valid - closing quotes aligned with content
        val code =
            """
            fun foo() = $MULTILINE_STRING_QUOTE
                bar
                $MULTILINE_STRING_QUOTE.trimIndent()
            """.trimIndent()
        indentationRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Given a property with multiline string and closing quotes at one indent level`() {
        // This should also be valid - closing quotes aligned with content
        val code =
            """
            val foo = $MULTILINE_STRING_QUOTE
                bar
                $MULTILINE_STRING_QUOTE.trimIndent()
            """.trimIndent()
        indentationRuleAssertThat(code).hasNoLintViolations()
    }
}
"}

